import{_ as e,c as a,o,ag as r}from"./chunks/framework.DD2hp6gW.js";const u=JSON.parse('{"title":"Text Input Field","description":"","frontmatter":{},"headers":[],"relativePath":"fields/text.md","filePath":"fields/text.md","lastUpdated":null}'),i={name:"fields/text.md"};function n(l,t,s,d,c,h){return o(),a("div",null,t[0]||(t[0]=[r('<h1 id="text-input-field" tabindex="-1">Text Input Field <a class="header-anchor" href="#text-input-field" aria-label="Permalink to &quot;Text Input Field&quot;">​</a></h1><p>The <strong>Text Input</strong> field allows customers to enter a single line of text. It&#39;s the most common field type and is ideal for collecting short, freeform information.</p><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li>Monogram initials or custom engraving text</li><li>Custom names or titles to be printed on a product</li><li>Short gift messages or dedication text</li><li>Custom order references or SKU codes</li></ul><h2 id="field-settings" tabindex="-1">Field Settings <a class="header-anchor" href="#field-settings" aria-label="Permalink to &quot;Field Settings&quot;">​</a></h2><p>When you add a Text Input field and expand it in the builder, the following settings are available:</p><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The title displayed above the input on the product page (e.g., &quot;Enter Your Name&quot;).</td></tr><tr><td style="text-align:left;"><strong>Description</strong></td><td style="text-align:left;">Optional help text shown below the input to guide the customer.</td></tr><tr><td style="text-align:left;"><strong>Required</strong></td><td style="text-align:left;">When checked, the customer must fill in this field before adding the product to the cart. A red asterisk (*) will appear next to the label.</td></tr></tbody></table><h3 id="placeholder" tabindex="-1">Placeholder <a class="header-anchor" href="#placeholder" aria-label="Permalink to &quot;Placeholder&quot;">​</a></h3><p>You can set <strong>Placeholder</strong> text that appears as faded hint text inside the input box (e.g., &quot;Type your message here...&quot;). This text disappears as soon as the customer starts typing.</p><h3 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h3><p>Since the Text Input is not an options-based field, pricing is configured at the <strong>field level</strong>:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Price Type</strong></td><td style="text-align:left;">Choose how the field affects the product price. Available types: <strong>No Price</strong>, <strong>Flat Fee</strong>, <strong>Percentage of Base</strong>, <strong>Per Character</strong>, or <strong>Formula</strong>.</td></tr><tr><td style="text-align:left;"><strong>Price Amount</strong></td><td style="text-align:left;">The numeric value to apply. For a Flat Fee of $5.00, enter <code>5</code>. For a Percentage of 10%, enter <code>10</code>.</td></tr><tr><td style="text-align:left;"><strong>Formula</strong></td><td style="text-align:left;">(Only when Price Type is &quot;Formula&quot;) A math expression using placeholders like <code>[value]</code>, <code>[char_count]</code>, <code>[base_price]</code>, and <code>[quantity]</code>. Example: <code>[char_count] * 0.50</code> charges 50 cents per character.</td></tr></tbody></table><h3 id="restrictions" tabindex="-1">Restrictions <a class="header-anchor" href="#restrictions" aria-label="Permalink to &quot;Restrictions&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Min Length</strong></td><td style="text-align:left;">The minimum number of characters the customer must enter.</td></tr><tr><td style="text-align:left;"><strong>Max Length</strong></td><td style="text-align:left;">The maximum number of characters allowed.</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Use <strong>Per Character</strong> pricing together with <strong>Min/Max Length</strong> restrictions to create a controlled engraving or embroidery pricing model. For example, set a Min Length of 1, a Max Length of 20, and a Per Character price of $0.50.</p></div><h2 id="conditional-logic" tabindex="-1">Conditional Logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional Logic&quot;">​</a></h2><p>You can show or hide this field based on the value of another field in the same group. For example, you could hide a &quot;Custom Engraving Text&quot; field until the customer selects &quot;Yes&quot; on a &quot;Add Engraving?&quot; checkbox.</p><p>For full details on setting up rules, see the <a href="./../conditional-logic.html">Conditional Logic</a> page.</p>',19)]))}const p=e(i,[["render",n]]);export{u as __pageData,p as default};
